CREATE FUNCTION `fn_obtener_tecnico_disponible`() RETURNS int
    READS SQL DATA
    DETERMINISTIC
BEGIN

    DECLARE v_tecnico_id INT;



    SELECT u.ID_Usuario

    INTO v_tecnico_id

    FROM tbl_usuario u

    LEFT JOIN tbl_ticket t 

        ON u.ID_Usuario = t.FK_ID_Usuario_Tecnico

        AND t.Estado_Ticket = 1

    WHERE u.FK_ID_Rol = 3

      AND u.Estado_Usuario = 1

    GROUP BY u.ID_Usuario

    ORDER BY COUNT(t.ID_Ticket) ASC

    LIMIT 1;



    RETURN v_tecnico_id;

END ;;
