CREATE PROCEDURE `sp_admin_metricas_funcionarios`()
BEGIN

    SELECT

        (SELECT COUNT(*)

         FROM VW_ADMIN_TECNICOS) AS tecnicos,

        (SELECT COUNT(*)

         FROM VW_ADMIN_TECNICOS WHERE Estado_Usuario = 0) AS tecnicos_desactivados,

        (SELECT COUNT(*)

         FROM VW_ADMIN_ADMINISTRADORES) AS administradores;

END ;;
