    IN p_Documento VARCHAR(30)

)
BEGIN

    SELECT e.ID_Estudiante

    FROM tbl_estudiante e

    JOIN tbl_persona p ON e.FK_ID_Persona = p.ID_Persona

    WHERE p.Num_Doc_Persona = p_Documento;

