CREATE PROCEDURE `sp_insertar_auditoria`(

    IN p_tabla VARCHAR(100),

    IN p_evento VARCHAR(20),

    IN p_id_registro VARCHAR(50),

    IN p_datos_old JSON,

    IN p_datos_new JSON,

    IN p_ip VARCHAR(50),

    IN p_user_agent VARCHAR(255),

    IN p_id_usuario INT

)
BEGIN

    INSERT INTO tbl_auditoria (

        Tabla_Afectada,

        Tipo_Evento,

        ID_Registro_Afectado,

        Datos_Antiguo,

        Datos_Nuevos,

        IP_Usuario,

        User_Agent,

        FK_ID_Usuario

    )

    VALUES (

        p_tabla,

        p_evento,

        p_id_registro,

        p_datos_old,

        p_datos_new,

        p_ip,

        p_user_agent,

        p_id_usuario

    );

END ;;
