CREATE PROCEDURE `sp_obtener_datos_autenticacion`(

    IN p_nombre_usuario VARCHAR(50)

)
BEGIN

    SELECT 

        ID_Usuario, 

        Contraseña_Hash, 

        Intentos_Fallidos

    FROM tbl_usuario

    WHERE Nombre_Usuario = p_nombre_usuario

    LIMIT 1;

END ;;
