CREATE PROCEDURE `sp_perfil_estudiantes_por_acudiente`(IN p_id_usuario INT)
BEGIN

    SELECT *

    FROM vw_estudiante_detalle

    WHERE FK_ID_Acudiente = p_id_usuario

      AND Estado_Estudiante = 1

    ORDER BY Primer_Apellido, Primer_Nombre;

END ;;
