CREATE PROCEDURE `sp_registrar_exito_login`(IN p_id_usuario INT)
BEGIN

    UPDATE tbl_usuario

    SET Ultimo_Login = NOW(), Intentos_Fallidos = 0

    WHERE ID_Usuario = p_id_usuario;

END ;;
