CREATE PROCEDURE `sp_tbl_sesion_activa_cerrar_todas_sesiones`(

    IN p_id_usuario INT,

    IN p_jti_actual VARCHAR(64)   -- excluir la sesión actual

)
BEGIN

    UPDATE tbl_sesion_activa

    SET Activa = 0

    WHERE FK_ID_Usuario = p_id_usuario

      AND JTI <> p_jti_actual;

