    IN p_jti VARCHAR(64),

    IN p_dispositivo VARCHAR(255),

    IN p_ip VARCHAR(50)

)
BEGIN

    INSERT INTO tbl_sesion_activa (FK_ID_Usuario, JTI, Dispositivo, IP)

    VALUES (p_id_usuario, p_jti, p_dispositivo, p_ip)

    ON DUPLICATE KEY UPDATE Ultimo_Acceso = CURRENT_TIMESTAMP;

