CREATE PROCEDURE `sp_tbl_usuario_desactivar_mfa`(

    IN p_id_usuario INT

)
BEGIN

    UPDATE tbl_usuario

    SET MFA_Fecha_Configuracion = CURRENT_TIMESTAMP,

        MFA_Secret = NULL,

        MFA_Secret_Temp = NULL,

        Doble_Factor_Activo = 'INACTIVE'

    WHERE ID_Usuario = p_id_usuario;

END ;;
