DELIMITER ;;
CREATE PROCEDURE `sp_ticket_obtener_ultimo_numero`()
BEGIN

    SELECT COALESCE(

        MAX(CAST(SUBSTRING(ID_Ticket, 5) AS UNSIGNED)), 

        0

    ) AS ultimo_numero

    FROM tbl_ticket;

END ;;
