CREATE PROCEDURE `sp_usuario_verificar_existente`(

    IN p_Email VARCHAR(255),

    IN p_Documento INT

)
BEGIN

    SELECT 

        u.Nombre_Usuario,

        p.ID_Persona

    FROM tbl_usuario u

    JOIN tbl_persona p

    ON u.FK_ID_Persona = p.ID_Persona

    WHERE u.Nombre_Usuario = p_Email

    OR p.ID_Persona = p_Documento;

END ;;
